<template>
  <view class="p-4">
    <!-- 列表 -->
    <view
      v-for="item in list"
      :key="item.id"
      class="bg-white rounded-xl shadow-sm p-4 mb-3"
    >
      <!-- 封面图 -->
      <u-image
        v-if="item.coverUrl"
        :src="item.coverUrl"
        width="100%"
        height="160px"
        mode="aspectFill"
        class="rounded-lg mb-3"
        @click="viewCase(item)"
      ></u-image>

      <text class="font-semibold block">{{ item.title }}</text>
      <text class="text-sm text-gray-500 mt-1 block">
        疾病：{{ item.disease }} | 救助金额：{{ item.amount }}
      </text>
      <text class="text-sm mt-2 line-clamp-2 block">{{ item.summary }}</text>
      
      <view class="flex gap-2 mt-3">
        <u-button size="mini" plain @click="viewCase(item)">
          查看详情
        </u-button>
        <u-button size="mini" plain @click="downloadCase(item)">
          下载案例 PDF
        </u-button>
      </view>
    </view>

    <!-- 空状态 -->
    <u-empty v-if="!loading && list.length === 0" mode="data" text="暂无案例分享"></u-empty>

    <!-- 加载更多 -->
    <u-loadmore 
      :status="loadStatus" 
      :loading-text="'加载中...'"
      :loadmore-text="'上拉加载更多'"
      :nomore-text="'没有更多了'"
      @loadmore="onLoadMore"
    />
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 分页
const currentPage = ref(1)
const pageSize = ref(10)
const loadStatus = ref<'loading' | 'loadmore' | 'nomore'>('loadmore')

// 列表数据
const list = ref<any[]>([])
const loading = ref(false)

const fetchCases = async (isRefresh = false) => {
  if (isRefresh) {
    currentPage.value = 1
    list.value = []
  }
  
  if (loadStatus.value === 'nomore' && !isRefresh) return

  loading.value = true
  loadStatus.value = 'loading'
  
  try {
    const res = await request.get('/api/resource/charity/cases', {
      params: {
        page: currentPage.value,
        limit: pageSize.value
      }
    })
    
    const records = res.data.records || res.data.list || []
    list.value.push(...records)
    
    if (records.length < pageSize.value) {
      loadStatus.value = 'nomore'
    } else {
      loadStatus.value = 'loadmore'
      currentPage.value++
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/charity/CaseShare.vue:92','获取案例失败:', error)
    loadStatus.value = 'loadmore'
    uni.showToast({ title: '加载失败', icon: 'none' })
  } finally {
    loading.value = false
  }
}

const onLoadMore = () => {
  fetchCases()
}

const viewCase = (item: any) => {
  uni.navigateTo({
    url: `/pages/resource/charity/CaseShareDetail?id=${item.id}`
  })
}

const downloadCase = (item: any) => {
  if (item.pdfUrl) {
    uni.showLoading({ title: '下载中...' })
    uni.downloadFile({
      url: item.pdfUrl,
      success: (res) => {
        uni.hideLoading()
        if (res.statusCode === 200) {
          uni.openDocument({
            filePath: res.tempFilePath,
            showMenu: true
          })
        } else {
          uni.showToast({ title: '下载失败', icon: 'none' })
        }
      },
      fail: () => {
        uni.hideLoading()
        uni.showToast({ title: '下载失败', icon: 'none' })
      }
    })
  } else {
    uni.showToast({ title: '暂无PDF文件', icon: 'none' })
  }
}

onMounted(() => {
  fetchCases()
})
</script>

